    uint8_t key[] = "test_key";
    uint8_t value[] = "test_value";
    ASSERT_EQ(tidesdb_txn_put(txn1, cf, key, sizeof(key), value, sizeof(value), 0), 0);
    ASSERT_EQ(tidesdb_txn_commit(txn1), 0);

    /* we delete it twice */
