    /* first commit succeeds, second fails with write-write conflict */
    ASSERT_EQ(tidesdb_txn_commit(t1), 0);
    ASSERT_EQ(tidesdb_txn_commit(t2), TDB_ERR_CONFLICT);

    tidesdb_txn_free(t1);
