    ASSERT_TRUE(cf_a != NULL);
    ASSERT_TRUE(cf_b != NULL);

    uint8_t key[] = "shared_key";
    uint8_t val_a[] = "value_a";
    uint8_t val_b[] = "value_b";

    tidesdb_txn_t *txn = NULL;
