    ASSERT_EQ(tidesdb_txn_put(txn, cf_a, key, sizeof(key), val_a, sizeof(val_a), 0), 0);
    ASSERT_EQ(tidesdb_txn_put(txn, cf_b, key, sizeof(key), val_b, sizeof(val_b), 0), 0);
