static void test_replica_mode(void)
{
    cleanup_test_dir();

    const char *objstore_dir = "./test_replica_store";
    remove_directory(objstore_dir);

    {
        tidesdb_objstore_t *store = tidesdb_objstore_fs_create(objstore_dir);
        ASSERT_TRUE(store != NULL);

        tidesdb_objstore_config_t os_cfg = tidesdb_objstore_default_config();
        os_cfg.wal_sync_on_commit = 1; /* sync WAL on every commit for replica freshness */

        tidesdb_config_t config = tidesdb_default_config();
        config.db_path = TEST_DB_PATH;
        config.object_store = store;
        config.object_store_config = &os_cfg;
        config.unified_memtable_write_buffer_size = 4096;

        tidesdb_t *db = NULL;
        ASSERT_EQ(tidesdb_open(&config, &db), 0);

        tidesdb_column_family_config_t cf_config = tidesdb_default_column_family_config();
        ASSERT_EQ(tidesdb_create_column_family(db, "replica_cf", &cf_config), 0);
        tidesdb_column_family_t *cf = tidesdb_get_column_family(db, "replica_cf");
        ASSERT_TRUE(cf != NULL);

        for (int i = 0; i < 30; i++)
        {
            tidesdb_txn_t *txn = NULL;
            ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
            char key[64], value[128];
            snprintf(key, sizeof(key), "rkey_%04d", i);
            snprintf(value, sizeof(value), "rval_%04d", i);
            ASSERT_EQ(tidesdb_txn_put(txn, cf, (uint8_t *)key, strlen(key) + 1, (uint8_t *)value,
                                      strlen(value) + 1, 0),
                      0);
            ASSERT_EQ(tidesdb_txn_commit(txn), 0);
            tidesdb_txn_free(txn);
        }

        /* wait for flush */
        for (int w = 0; w < 200; w++)
        {
            if (queue_size(db->flush_queue) == 0 && !atomic_load(&db->unified_mt.is_flushing))
                break;
            usleep(20000);
        }
        usleep(200000);

        tidesdb_close(db);
    }

    printf("  replica: primary wrote 30 keys and uploaded to store\n");

    /* we open as replica and verify reads work and writes are rejected */
    cleanup_test_dir();

    {
        tidesdb_objstore_t *store2 = tidesdb_objstore_fs_create(objstore_dir);
        ASSERT_TRUE(store2 != NULL);

        tidesdb_objstore_config_t os_cfg = tidesdb_objstore_default_config();
        os_cfg.replica_mode = 1;
        os_cfg.replica_replay_wal = 1;
        os_cfg.replica_sync_interval_us = 100000; /* 100ms for fast test */

        tidesdb_config_t config = tidesdb_default_config();
        config.db_path = TEST_DB_PATH;
        config.object_store = store2;
        config.object_store_config = &os_cfg;
        config.unified_memtable_write_buffer_size = 4096;

        tidesdb_t *db = NULL;
        ASSERT_EQ(tidesdb_open(&config, &db), 0);

        /* we verify replica mode is active */
        tidesdb_db_stats_t stats;
        ASSERT_EQ(tidesdb_get_db_stats(db, &stats), 0);
        ASSERT_TRUE(stats.replica_mode == 1);

        /* cold start should have discovered the CF */
        tidesdb_column_family_t *cf = tidesdb_get_column_family(db, "replica_cf");
        ASSERT_TRUE(cf != NULL);

        /* we read data */
        tidesdb_txn_t *txn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        int found = 0;
        for (int i = 0; i < 30; i++)
        {
            char key[64];
            snprintf(key, sizeof(key), "rkey_%04d", i);
            uint8_t *val = NULL;
            size_t val_size = 0;
            if (tidesdb_txn_get(txn, cf, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 &&
                val)
            {
                found++;
                free(val);
            }
        }
        tidesdb_txn_free(txn);
        printf("  replica: read back %d/30 keys\n", found);
        ASSERT_TRUE(found > 0);

        /* verify writes are rejected */
        tidesdb_txn_t *wtxn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &wtxn), 0);
        int put_rc = tidesdb_txn_put(wtxn, cf, (uint8_t *)"blocked", 8, (uint8_t *)"nope", 5, 0);
        ASSERT_EQ(put_rc, TDB_ERR_READONLY);
        printf("  replica: write correctly rejected with TDB_ERR_READONLY\n");
        tidesdb_txn_free(wtxn);

        /* we promote to primary and verify writes work */
        ASSERT_EQ(tidesdb_promote_to_primary(db), 0);

        tidesdb_txn_t *ptxn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &ptxn), 0);
        ASSERT_EQ(tidesdb_txn_put(ptxn, cf, (uint8_t *)"promoted_key", 13,
                                  (uint8_t *)"promoted_val", 13, 0),
                  0);
        ASSERT_EQ(tidesdb_txn_commit(ptxn), 0);
        tidesdb_txn_free(ptxn);
        printf("  replica: promoted to primary, write succeeded\n");

        /* verify the promoted write is readable */
        tidesdb_txn_t *rtxn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &rtxn), 0);
        uint8_t *pval = NULL;
        size_t pval_size = 0;
        ASSERT_EQ(tidesdb_txn_get(rtxn, cf, (uint8_t *)"promoted_key", 13, &pval, &pval_size), 0);
        ASSERT_TRUE(pval != NULL);
        free(pval);
        tidesdb_txn_free(rtxn);

        tidesdb_close(db);
    }

    remove_directory(objstore_dir);
    cleanup_test_dir();
}

static void test_primary_replica_failover(void)
{
    cleanup_test_dir();

    const char *objstore_dir = "./test_failover_store";
    remove_directory(objstore_dir);

    const int NUM_KEYS_PHASE1 = 50;
    const int NUM_KEYS_PHASE2 = 20;

    /* primary writes data to two CFs */
    {
        tidesdb_objstore_t *store = tidesdb_objstore_fs_create(objstore_dir);
        ASSERT_TRUE(store != NULL);

        tidesdb_objstore_config_t os_cfg = tidesdb_objstore_default_config();
        os_cfg.wal_sync_on_commit = 1;

        tidesdb_config_t config = tidesdb_default_config();
        config.db_path = TEST_DB_PATH;
        config.object_store = store;
        config.object_store_config = &os_cfg;
        config.unified_memtable_write_buffer_size = 4096;

        tidesdb_t *db = NULL;
        ASSERT_EQ(tidesdb_open(&config, &db), 0);

        tidesdb_column_family_config_t cf_config = tidesdb_default_column_family_config();
        ASSERT_EQ(tidesdb_create_column_family(db, "failover_cf1", &cf_config), 0);
        tidesdb_column_family_t *cf1 = tidesdb_get_column_family(db, "failover_cf1");
        ASSERT_TRUE(cf1 != NULL);

        /* write first batch to cf1 */
        for (int i = 0; i < NUM_KEYS_PHASE1; i++)
        {
            tidesdb_txn_t *txn = NULL;
            ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
            char key[64], value[128];
            snprintf(key, sizeof(key), "fkey_%04d", i);
            snprintf(value, sizeof(value), "fval_%04d", i);
            ASSERT_EQ(tidesdb_txn_put(txn, cf1, (uint8_t *)key, strlen(key) + 1, (uint8_t *)value,
                                      strlen(value) + 1, 0),
                      0);
            ASSERT_EQ(tidesdb_txn_commit(txn), 0);
            tidesdb_txn_free(txn);
        }

        /* create second CF mid-flight (replica must discover this) */
        ASSERT_EQ(tidesdb_create_column_family(db, "failover_cf2", &cf_config), 0);
        tidesdb_column_family_t *cf2 = tidesdb_get_column_family(db, "failover_cf2");
        ASSERT_TRUE(cf2 != NULL);

        for (int i = 0; i < 10; i++)
        {
            tidesdb_txn_t *txn = NULL;
            ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
            char key[64], value[128];
            snprintf(key, sizeof(key), "cf2key_%04d", i);
            snprintf(value, sizeof(value), "cf2val_%04d", i);
            ASSERT_EQ(tidesdb_txn_put(txn, cf2, (uint8_t *)key, strlen(key) + 1, (uint8_t *)value,
                                      strlen(value) + 1, 0),
                      0);
            ASSERT_EQ(tidesdb_txn_commit(txn), 0);
            tidesdb_txn_free(txn);
        }

        /* wait for flushes */
        for (int w = 0; w < 200; w++)
        {
            if (queue_size(db->flush_queue) == 0 && !atomic_load(&db->unified_mt.is_flushing))
                break;
            usleep(20000);
        }
        usleep(200000);

        tidesdb_close(db);
        printf("  failover: primary wrote %d keys to cf1, 10 keys to cf2\n", NUM_KEYS_PHASE1);
    }

    /* replica opens, syncs, reads, promotes, writes */
    cleanup_test_dir();

    {
        tidesdb_objstore_t *store2 = tidesdb_objstore_fs_create(objstore_dir);
        ASSERT_TRUE(store2 != NULL);

        tidesdb_objstore_config_t os_cfg = tidesdb_objstore_default_config();
        os_cfg.replica_mode = 1;
        os_cfg.replica_replay_wal = 1;
        os_cfg.replica_sync_interval_us = 100000; /* 100ms */

        tidesdb_config_t config = tidesdb_default_config();
        config.db_path = TEST_DB_PATH;
        config.object_store = store2;
        config.object_store_config = &os_cfg;
        config.unified_memtable_write_buffer_size = 4096;

        tidesdb_t *db = NULL;
        ASSERT_EQ(tidesdb_open(&config, &db), 0);

        /* wait for at least one sync cycle */
        usleep(300000);

        /* verify both CFs were discovered */
        tidesdb_column_family_t *cf1 = tidesdb_get_column_family(db, "failover_cf1");
        ASSERT_TRUE(cf1 != NULL);
        tidesdb_column_family_t *cf2 = tidesdb_get_column_family(db, "failover_cf2");
        ASSERT_TRUE(cf2 != NULL);
        printf("  failover: replica discovered both CFs\n");

        /* read cf1 data */
        tidesdb_txn_t *txn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        int found_cf1 = 0;
        for (int i = 0; i < NUM_KEYS_PHASE1; i++)
        {
            char key[64];
            snprintf(key, sizeof(key), "fkey_%04d", i);
            uint8_t *val = NULL;
            size_t val_size = 0;
            if (tidesdb_txn_get(txn, cf1, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 &&
                val)
            {
                found_cf1++;
                free(val);
            }
        }
        tidesdb_txn_free(txn);
        printf("  failover: replica read %d/%d keys from cf1\n", found_cf1, NUM_KEYS_PHASE1);
        ASSERT_TRUE(found_cf1 > 0);

        /* read cf2 data */
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        int found_cf2 = 0;
        for (int i = 0; i < 10; i++)
        {
            char key[64];
            snprintf(key, sizeof(key), "cf2key_%04d", i);
            uint8_t *val = NULL;
            size_t val_size = 0;
            if (tidesdb_txn_get(txn, cf2, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 &&
                val)
            {
                found_cf2++;
                free(val);
            }
        }
        tidesdb_txn_free(txn);
        printf("  failover: replica read %d/10 keys from cf2\n", found_cf2);
        ASSERT_TRUE(found_cf2 > 0);

        /* verify writes rejected in replica mode */
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        ASSERT_EQ(tidesdb_txn_put(txn, cf1, (uint8_t *)"blocked", 8, (uint8_t *)"no", 3, 0),
                  TDB_ERR_READONLY);
        tidesdb_txn_free(txn);

        /* promote to primary */
        ASSERT_EQ(tidesdb_promote_to_primary(db), 0);
        printf("  failover: promoted to primary\n");

        /* write new data immediately after promotion */
        for (int i = 0; i < NUM_KEYS_PHASE2; i++)
        {
            ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
            char key[64], value[128];
            snprintf(key, sizeof(key), "newkey_%04d", i);
            snprintf(value, sizeof(value), "newval_%04d", i);
            ASSERT_EQ(tidesdb_txn_put(txn, cf1, (uint8_t *)key, strlen(key) + 1, (uint8_t *)value,
                                      strlen(value) + 1, 0),
                      0);
            ASSERT_EQ(tidesdb_txn_commit(txn), 0);
            tidesdb_txn_free(txn);
        }
        printf("  failover: wrote %d new keys after promotion\n", NUM_KEYS_PHASE2);

        /* write to cf2 after promotion */
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        ASSERT_EQ(
            tidesdb_txn_put(txn, cf2, (uint8_t *)"cf2_promoted", 13, (uint8_t *)"cf2_pval", 9, 0),
            0);
        ASSERT_EQ(tidesdb_txn_commit(txn), 0);
        tidesdb_txn_free(txn);

        /* verify all data readable old cf1 + new cf1 + cf2 */
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);

        int total_cf1 = 0;
        for (int i = 0; i < NUM_KEYS_PHASE1; i++)
        {
            char key[64];
            snprintf(key, sizeof(key), "fkey_%04d", i);
            uint8_t *val = NULL;
            size_t val_size = 0;
            if (tidesdb_txn_get(txn, cf1, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 &&
                val)
            {
                total_cf1++;
                free(val);
            }
        }
        for (int i = 0; i < NUM_KEYS_PHASE2; i++)
        {
            char key[64];
            snprintf(key, sizeof(key), "newkey_%04d", i);
            uint8_t *val = NULL;
            size_t val_size = 0;
            if (tidesdb_txn_get(txn, cf1, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 &&
                val)
            {
                total_cf1++;
                free(val);
            }
        }

        uint8_t *cf2_pval = NULL;
        size_t cf2_pval_size = 0;
        int cf2_promoted_ok =
            tidesdb_txn_get(txn, cf2, (uint8_t *)"cf2_promoted", 13, &cf2_pval, &cf2_pval_size);

        tidesdb_txn_free(txn);

        printf("  failover: verified %d/%d total cf1 keys (old + new)\n", total_cf1,
               NUM_KEYS_PHASE1 + NUM_KEYS_PHASE2);
        ASSERT_TRUE(total_cf1 >= NUM_KEYS_PHASE2); /* at minimum the new keys must be there */
        ASSERT_EQ(cf2_promoted_ok, 0);
        ASSERT_TRUE(cf2_pval != NULL);
        free(cf2_pval);
        printf("  failover: cf2 post-promotion write verified\n");

        tidesdb_close(db);
    }

    remove_directory(objstore_dir);
    cleanup_test_dir();
}

static void test_btree_multi_cf_vlog_isolation(void)
{
    cleanup_test_dir();

    tidesdb_config_t config = tidesdb_default_config();
    config.db_path = TEST_DB_PATH;
    config.unified_memtable = 1;
    config.unified_memtable_write_buffer_size = 256 * 1024;
    config.log_level = TDB_LOG_WARN;

    tidesdb_t *db = NULL;
    ASSERT_EQ(tidesdb_open(&config, &db), 0);

    /* btree with small values (inline, under threshold) */
    tidesdb_column_family_config_t cfg1 = tidesdb_default_column_family_config();
    cfg1.use_btree = 1;
    cfg1.write_buffer_size = 256 * 1024;
    cfg1.klog_value_threshold = 512;
    cfg1.compression_algorithm = TDB_COMPRESS_NONE;
    ASSERT_EQ(tidesdb_create_column_family(db, "bt_small", &cfg1), 0);

    /* btree with large values (vlog, over threshold) */
    tidesdb_column_family_config_t cfg2 = tidesdb_default_column_family_config();
    cfg2.use_btree = 1;
    cfg2.write_buffer_size = 256 * 1024;
    cfg2.klog_value_threshold = 512;
    cfg2.compression_algorithm = TDB_COMPRESS_NONE;
    ASSERT_EQ(tidesdb_create_column_family(db, "bt_large", &cfg2), 0);

    tidesdb_column_family_t *cf_small = tidesdb_get_column_family(db, "bt_small");
    tidesdb_column_family_t *cf_large = tidesdb_get_column_family(db, "bt_large");
    ASSERT_TRUE(cf_small != NULL);
    ASSERT_TRUE(cf_large != NULL);

    const int NUM = 500;
    const int SMALL_SIZE = 64;
    const int LARGE_SIZE = 2048;

    uint8_t *small_val = malloc(SMALL_SIZE);
    uint8_t *large_val = malloc(LARGE_SIZE);
    ASSERT_TRUE(small_val != NULL && large_val != NULL);

    /* we write same keys to both CFs with different value sizes */
    for (int i = 0; i < NUM; i++)
    {
        char key[64];
        snprintf(key, sizeof(key), "shared_key_%06d", i);

        /* we fill with deterministic patterns */
        for (int j = 0; j < SMALL_SIZE; j++) small_val[j] = (uint8_t)((i * 17 + j * 3) & 0xFF);
        for (int j = 0; j < LARGE_SIZE; j++) large_val[j] = (uint8_t)((i * 41 + j * 11) & 0xFF);

        tidesdb_txn_t *txn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        ASSERT_EQ(tidesdb_txn_put(txn, cf_small, (uint8_t *)key, strlen(key) + 1, small_val,
                                  SMALL_SIZE, 0),
                  0);
        ASSERT_EQ(tidesdb_txn_put(txn, cf_large, (uint8_t *)key, strlen(key) + 1, large_val,
                                  LARGE_SIZE, 0),
                  0);
        ASSERT_EQ(tidesdb_txn_commit(txn), 0);
        tidesdb_txn_free(txn);
    }

    /* we force flush to sstables */
    tidesdb_purge_cf(cf_small);
    tidesdb_purge_cf(cf_large);

    /* we wait for background flush */
    for (int w = 0; w < 100; w++)
    {
        if (queue_size(db->flush_queue) == 0 && !atomic_load(&db->unified_mt.is_flushing)) break;
        usleep(50000);
    }
    usleep(500000);

    /* we verify CF1 (small values, inline) */
    printf("  verifying small CF (%d entries, %d bytes each)...\n", NUM, SMALL_SIZE);
    int small_ok = 0;
    for (int i = 0; i < NUM; i++)
    {
        char key[64];
        snprintf(key, sizeof(key), "shared_key_%06d", i);

        tidesdb_txn_t *txn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        uint8_t *rv = NULL;
        size_t rs = 0;
        int rc = tidesdb_txn_get(txn, cf_small, (uint8_t *)key, strlen(key) + 1, &rv, &rs);
        tidesdb_txn_free(txn);

        if (rc != 0)
        {
            printf("  FAIL: key %d not found (rc=%d)\n", i, rc);
            ASSERT_EQ(rc, 0);
        }
        if (rs != (size_t)SMALL_SIZE)
        {
            printf("  FAIL: key %d size mismatch: got %zu expected %d, value=%p\n", i, rs,
                   SMALL_SIZE, (void *)rv);
            if (rv && rs > 0)
            {
                printf("  first bytes: %02x %02x %02x %02x\n", rv[0], rs > 1 ? rv[1] : 0,
                       rs > 2 ? rv[2] : 0, rs > 3 ? rv[3] : 0);
            }
            free(rv);
            ASSERT_EQ(rs, (size_t)SMALL_SIZE);
        }

        for (int j = 0; j < SMALL_SIZE; j++) small_val[j] = (uint8_t)((i * 17 + j * 3) & 0xFF);
        ASSERT_TRUE(memcmp(rv, small_val, SMALL_SIZE) == 0);
        free(rv);
        small_ok++;
    }
    printf("  small CF: %d/%d OK\n", small_ok, NUM);

    /* we verify CF2 (large values, vlog) */
    printf("  verifying large CF (%d entries, %d bytes each)...\n", NUM, LARGE_SIZE);
    int large_ok = 0;
    for (int i = 0; i < NUM; i++)
    {
        char key[64];
        snprintf(key, sizeof(key), "shared_key_%06d", i);

        tidesdb_txn_t *txn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        uint8_t *rv = NULL;
        size_t rs = 0;
        int rc = tidesdb_txn_get(txn, cf_large, (uint8_t *)key, strlen(key) + 1, &rv, &rs);
        tidesdb_txn_free(txn);

        ASSERT_EQ(rc, 0);
        ASSERT_EQ(rs, (size_t)LARGE_SIZE);

        for (int j = 0; j < LARGE_SIZE; j++) large_val[j] = (uint8_t)((i * 41 + j * 11) & 0xFF);
        ASSERT_TRUE(memcmp(rv, large_val, LARGE_SIZE) == 0);
        free(rv);
        large_ok++;
    }
    printf("  large CF: %d/%d OK\n", large_ok, NUM);

    free(small_val);
    free(large_val);
    tidesdb_close(db);
    cleanup_test_dir();
}

#ifdef TIDESDB_WITH_S3
#include "../src/objstore_s3.h"

static void tdb_cf_list_noop_cb(const char *key, size_t size, void *cb_ctx)
{
    (void)key;
    (void)size;
    (void)cb_ctx;
}

static void test_objstore_s3_minio(void)
{
    const char *endpoint = getenv("TIDESDB_S3_ENDPOINT");
    const char *bucket = getenv("TIDESDB_S3_BUCKET");
    const char *access_key = getenv("TIDESDB_S3_ACCESS_KEY");
    const char *secret_key = getenv("TIDESDB_S3_SECRET_KEY");

    if (!endpoint || !bucket || !access_key || !secret_key)
    {
        printf("  S3 test skipped (TIDESDB_S3_* env vars not set)\n");
        return;
    }

    cleanup_test_dir();

    printf("  S3 test: connecting to %s bucket=%s\n", endpoint, bucket);

    tidesdb_objstore_t *s3 =
        tidesdb_objstore_s3_create(endpoint, bucket, "tidesdb_test/", access_key, secret_key,
                                   NULL, /* region (NULL for MinIO) */
                                   0,    /* use_ssl = 0 for local MinIO */
                                   1     /* use_path_style = 1 for MinIO */
        );
    ASSERT_TRUE(s3 != NULL);

    /* test raw connector operations first */

    /* put a small test file */
    const char *test_file = "./test_s3_upload.tmp";
    FILE *fp = fopen(test_file, "wb");
    ASSERT_TRUE(fp != NULL);
    fprintf(fp, "hello from tidesdb s3 test");
    fclose(fp);

    ASSERT_EQ(s3->put(s3->ctx, "test/hello.txt", test_file), 0);
    printf("  S3 test: put succeeded\n");

    /* exists */
    size_t obj_size = 0;
    ASSERT_TRUE(s3->exists(s3->ctx, "test/hello.txt", &obj_size) == 1);
    ASSERT_TRUE(obj_size > 0);
    printf("  S3 test: exists succeeded (size=%zu)\n", obj_size);

    /* get */
    const char *download_file = "./test_s3_download.tmp";
    ASSERT_EQ(s3->get(s3->ctx, "test/hello.txt", download_file), 0);
    fp = fopen(download_file, "rb");
    ASSERT_TRUE(fp != NULL);
    char buf[256] = {0};
    size_t fread_n = fread(buf, 1, sizeof(buf) - 1, fp);
    (void)fread_n;
    fclose(fp);
    ASSERT_TRUE(strstr(buf, "hello from tidesdb") != NULL);
    printf("  S3 test: get succeeded\n");

    /* range_get */
    char range_buf[10] = {0};
    ssize_t nread = s3->range_get(s3->ctx, "test/hello.txt", 0, range_buf, 5);
    ASSERT_TRUE(nread >= 5);
    ASSERT_TRUE(memcmp(range_buf, "hello", 5) == 0);
    printf("  S3 test: range_get succeeded\n");

    /* list */
    int list_count = s3->list(s3->ctx, "", tdb_cf_list_noop_cb, NULL);
    ASSERT_TRUE(list_count >= 1);
    printf("  S3 test: list succeeded (count=%d)\n", list_count);

    /* delete */
    ASSERT_EQ(s3->delete_object(s3->ctx, "test/hello.txt"), 0);
    ASSERT_TRUE(s3->exists(s3->ctx, "test/hello.txt", NULL) == 0);
    printf("  S3 test: delete succeeded\n");

    /* clean up temp files */
    unlink(test_file);
    unlink(download_file);

    /* now test full database roundtrip through S3 */
    tidesdb_objstore_config_t os_cfg = tidesdb_objstore_default_config();

    tidesdb_config_t config = tidesdb_default_config();
    config.db_path = TEST_DB_PATH;
    config.object_store = s3;
    config.object_store_config = &os_cfg;
    config.unified_memtable_write_buffer_size = 4096;

    tidesdb_t *db = NULL;
    ASSERT_EQ(tidesdb_open(&config, &db), 0);

    tidesdb_column_family_config_t cf_config = tidesdb_default_column_family_config();
    ASSERT_EQ(tidesdb_create_column_family(db, "s3_cf", &cf_config), 0);
    tidesdb_column_family_t *cf = tidesdb_get_column_family(db, "s3_cf");
    ASSERT_TRUE(cf != NULL);

    /* write enough data to trigger unified flush */
    const int NUM_KEYS = 50;
    for (int i = 0; i < NUM_KEYS; i++)
    {
        tidesdb_txn_t *txn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
        char key[64], value[256];
        snprintf(key, sizeof(key), "s3key_%06d", i);
        memset(value, 'S' + (i % 20), sizeof(value) - 1);
        value[sizeof(value) - 1] = '\0';
        ASSERT_EQ(tidesdb_txn_put(txn, cf, (uint8_t *)key, strlen(key) + 1, (uint8_t *)value,
                                  strlen(value) + 1, 0),
                  0);
        ASSERT_EQ(tidesdb_txn_commit(txn), 0);
        tidesdb_txn_free(txn);
    }

    /* wait for flush */
    for (int w = 0; w < 200; w++)
    {
        if (queue_size(db->flush_queue) == 0 && !atomic_load(&db->unified_mt.is_flushing)) break;
        usleep(20000);
    }
    usleep(500000);

    /* trigger compaction */
    tidesdb_compact(cf);
    for (int w = 0; w < 200; w++)
    {
        if (!atomic_load(&cf->is_compacting)) break;
        usleep(20000);
    }

    /* delete every 5th key */
    for (int i = 0; i < NUM_KEYS; i += 5)
    {
        tidesdb_txn_t *dtxn = NULL;
        ASSERT_EQ(tidesdb_txn_begin(db, &dtxn), 0);
        char key[64];
        snprintf(key, sizeof(key), "s3key_%06d", i);
        ASSERT_EQ(tidesdb_txn_delete(dtxn, cf, (uint8_t *)key, strlen(key) + 1), 0);
        ASSERT_EQ(tidesdb_txn_commit(dtxn), 0);
        tidesdb_txn_free(dtxn);
    }

    /* wait for any flush from deletes */
    for (int w = 0; w < 200; w++)
    {
        if (queue_size(db->flush_queue) == 0 && !atomic_load(&db->unified_mt.is_flushing)) break;
        usleep(20000);
    }
    usleep(300000);

    /* point lookup every key */
    tidesdb_txn_t *txn = NULL;
    ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
    int found = 0;
    for (int i = 0; i < NUM_KEYS; i++)
    {
        char key[64];
        snprintf(key, sizeof(key), "s3key_%06d", i);
        uint8_t *val = NULL;
        size_t val_size = 0;
        if (tidesdb_txn_get(txn, cf, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 && val)
        {
            found++;
            free(val);
        }
    }
    printf("  S3 test: point lookup found %d/%d keys after deletes\n", found, NUM_KEYS);
    ASSERT_TRUE(found > 0);
    ASSERT_TRUE(found < NUM_KEYS); /* some should be deleted */

    /* forward iteration */
    tidesdb_iter_t *iter = NULL;
    ASSERT_EQ(tidesdb_iter_new(txn, cf, &iter), 0);
    ASSERT_EQ(tidesdb_iter_seek_to_first(iter), 0);
    int fwd_count = 0;
    while (tidesdb_iter_valid(iter))
    {
        fwd_count++;
        tidesdb_iter_next(iter);
    }

    /* backward iteration */
    ASSERT_EQ(tidesdb_iter_seek_to_last(iter), 0);
    int bwd_count = 0;
    while (tidesdb_iter_valid(iter))
    {
        bwd_count++;
        tidesdb_iter_prev(iter);
    }

    /* seek to middle */
    char mid_key[64];
    snprintf(mid_key, sizeof(mid_key), "s3key_%06d", NUM_KEYS / 2);
    ASSERT_EQ(tidesdb_iter_seek(iter, (uint8_t *)mid_key, strlen(mid_key) + 1), 0);
    ASSERT_TRUE(tidesdb_iter_valid(iter));

    tidesdb_iter_free(iter);
    tidesdb_txn_free(txn);

    printf("  S3 test: fwd=%d bwd=%d (point=%d)\n", fwd_count, bwd_count, found);
    ASSERT_TRUE(fwd_count > 0);
    ASSERT_TRUE(bwd_count > 0);

    /* check stats */
    tidesdb_db_stats_t stats;
    ASSERT_EQ(tidesdb_get_db_stats(db, &stats), 0);
    ASSERT_TRUE(stats.object_store_enabled == 1);
    ASSERT_TRUE(stats.total_uploads > 0);
    printf("  S3 test: stats show %" PRIu64 " uploads via connector '%s'\n", stats.total_uploads,
           stats.object_store_connector ? stats.object_store_connector : "?");

    tidesdb_close(db);

    /* cold start test -- we delete all local state, reopen from S3 */
    cleanup_test_dir();

    tidesdb_objstore_t *s3_recover = tidesdb_objstore_s3_create(endpoint, bucket, "tidesdb_test/",
                                                                access_key, secret_key, NULL, 0, 1);
    ASSERT_TRUE(s3_recover != NULL);

    config.object_store = s3_recover;
    db = NULL;
    ASSERT_EQ(tidesdb_open(&config, &db), 0);

    cf = tidesdb_get_column_family(db, "s3_cf");
    ASSERT_TRUE(cf != NULL);

    txn = NULL;
    ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
    int cold_found = 0;
    for (int i = 0; i < NUM_KEYS; i++)
    {
        char key[64];
        snprintf(key, sizeof(key), "s3key_%06d", i);
        uint8_t *val = NULL;
        size_t val_size = 0;
        if (tidesdb_txn_get(txn, cf, (uint8_t *)key, strlen(key) + 1, &val, &val_size) == 0 && val)
        {
            cold_found++;
            free(val);
        }
    }
    tidesdb_txn_free(txn);
    printf("  S3 test: cold start recovery read back %d/%d keys from MinIO\n", cold_found,
           NUM_KEYS);
    ASSERT_TRUE(cold_found > 0);

    tidesdb_close(db);

    cleanup_test_dir();
}
#endif /* TIDESDB_WITH_S3 */

/* helpers shared by the tombstone density tests below */
static void wait_for_flush_complete(tidesdb_t *db, tidesdb_column_family_t *cf)
{
    /*** is_flushing is the brief rotate gate, cleared by the writer once the
     **  work is enqueued, so polling it returns success before the worker has
     *   actually written the sstable. flush_pending_count is incremented
     **  before enqueue and decremented only after the worker finishes the
     *** sstable write and level/manifest updates, so it is the right fence
     **  for observably complete flush. */
    wait_for_flush_queue_drain(db);
    const int max_wait = 200;
    for (int i = 0; i < max_wait; i++)
    {
        if (atomic_load_explicit(&db->flush_pending_count, memory_order_acquire) == 0 &&
            queue_size(db->flush_queue) == 0)
        {
            usleep(20000);
            break;
        }
        usleep(20000);
    }
    (void)cf;
}

static void td_put(tidesdb_t *db, tidesdb_column_family_t *cf, int i)
{
    tidesdb_txn_t *txn = NULL;
    ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
    char key[32];
    char value[64];
    snprintf(key, sizeof(key), "tdkey_%06d", i);
    snprintf(value, sizeof(value), "tdval_%06d", i);
    ASSERT_EQ(tidesdb_txn_put(txn, cf, (uint8_t *)key, strlen(key) + 1, (uint8_t *)value,
                              strlen(value) + 1, 0),
              0);
    ASSERT_EQ(tidesdb_txn_commit(txn), 0);
    tidesdb_txn_free(txn);
}

static void td_delete(tidesdb_t *db, tidesdb_column_family_t *cf, int i)
{
    tidesdb_txn_t *txn = NULL;
    ASSERT_EQ(tidesdb_txn_begin(db, &txn), 0);
    char key[32];
    snprintf(key, sizeof(key), "tdkey_%06d", i);
    ASSERT_EQ(tidesdb_txn_delete(txn, cf, (uint8_t *)key, strlen(key) + 1), 0);
    ASSERT_EQ(tidesdb_txn_commit(txn), 0);
    tidesdb_txn_free(txn);
}

static void test_tombstone_count_after_flush(void)
{
    cleanup_test_dir();
    tidesdb_t *db = create_test_db();
    tidesdb_column_family_config_t cf_config = tidesdb_default_column_family_config();
    cf_config.compression_algorithm = TDB_COMPRESS_NONE;

    ASSERT_EQ(tidesdb_create_column_family(db, "tcaf_cf", &cf_config), 0);
    tidesdb_column_family_t *cf = tidesdb_get_column_family(db, "tcaf_cf");
    ASSERT_TRUE(cf != NULL);

    const int num_keys = 100;
    const int num_deletes = 60;

    for (int i = 0; i < num_keys; i++) td_put(db, cf, i);
    /* flush before issuing deletes so puts and deletes don't collapse in the memtable */
    tidesdb_flush_memtable(cf);
    wait_for_flush_complete(db, cf);

    for (int i = 0; i < num_deletes; i++) td_delete(db, cf, i);
    tidesdb_flush_memtable(cf);
    wait_for_flush_complete(db, cf);

    tidesdb_stats_t *stats = NULL;
    ASSERT_EQ(tidesdb_get_stats(cf, &stats), 0);
    ASSERT_TRUE(stats != NULL);
    ASSERT_TRUE(stats->total_tombstones >= (uint64_t)num_deletes);
    ASSERT_TRUE(stats->total_keys >= (uint64_t)num_keys);
    tidesdb_free_stats(stats);

    ASSERT_EQ(tidesdb_close(db), TDB_SUCCESS);
    cleanup_test_dir();
}

static void test_tombstone_count_round_trip(void)
{
    cleanup_test_dir();
    tidesdb_config_t config = tidesdb_default_config();
    config.db_path = TEST_DB_PATH;

    tidesdb_t *db = NULL;
    ASSERT_EQ(tidesdb_open(&config, &db), TDB_SUCCESS);
    ASSERT_TRUE(db != NULL);

    tidesdb_column_family_config_t cf_config = tidesdb_default_column_family_config();
    cf_config.compression_algorithm = TDB_COMPRESS_NONE;
    ASSERT_EQ(tidesdb_create_column_family(db, "tcrt_cf", &cf_config), 0);
    tidesdb_column_family_t *cf = tidesdb_get_column_family(db, "tcrt_cf");
    ASSERT_TRUE(cf != NULL);

    const int num_keys = 80;
    const int num_deletes = 50;
    for (int i = 0; i < num_keys; i++) td_put(db, cf, i);
    tidesdb_flush_memtable(cf);
    wait_for_flush_complete(db, cf);
    for (int i = 0; i < num_deletes; i++) td_delete(db, cf, i);
    tidesdb_flush_memtable(cf);
    wait_for_flush_complete(db, cf);

    tidesdb_stats_t *before = NULL;
    ASSERT_EQ(tidesdb_get_stats(cf, &before), 0);
    const uint64_t expected = before->total_tombstones;
    ASSERT_TRUE(expected > 0);
    tidesdb_free_stats(before);

    ASSERT_EQ(tidesdb_close(db), TDB_SUCCESS);

    /* reopen and confirm the count was recovered from the sstable footers */
    db = NULL;
    ASSERT_EQ(tidesdb_open(&config, &db), TDB_SUCCESS);
    cf = tidesdb_get_column_family(db, "tcrt_cf");
    ASSERT_TRUE(cf != NULL);

    tidesdb_stats_t *after = NULL;
    ASSERT_EQ(tidesdb_get_stats(cf, &after), 0);
    ASSERT_EQ((int)after->total_tombstones, (int)expected);
    tidesdb_free_stats(after);

    ASSERT_EQ(tidesdb_close(db), TDB_SUCCESS);
    cleanup_test_dir();
}

static void test_tombstone_density_trigger_fires(void)
{
    cleanup_test_dir();
    tidesdb_t *db = create_test_db();
    tidesdb_column_family_config_t cf_config = tidesdb_default_column_family_config();
    cf_config.compression_algorithm = TDB_COMPRESS_NONE;
    /* keep structural triggers far out of reach so only the density signal can fire */
    cf_config.l1_file_count_trigger = 1000;
    cf_config.write_buffer_size = 4096;
    cf_config.tombstone_density_trigger = 0.5;
    cf_config.tombstone_density_min_entries = 8;

    ASSERT_EQ(tidesdb_create_column_family(db, "tdtf_cf", &cf_config), 0);
    tidesdb_column_family_t *cf = tidesdb_get_column_family(db, "tdtf_cf");
    ASSERT_TRUE(cf != NULL);

    const int num_keys = 100;
    const int num_deletes = 80;

    for (int i = 0; i < num_keys; i++) td_put(db, cf, i);
    tidesdb_flush_memtable(cf);
    wait_for_flush_complete(db, cf);

    for (int i = 0; i < num_deletes; i++) td_delete(db, cf, i);
    tidesdb_flush_memtable(cf);
    wait_for_flush_complete(db, cf);
    wait_for_compaction_idle(db, cf);

    /* the density trigger must have run a compaction even though l1_file_count_trigger
     * is 1000 -- after settling, the post-flush trigger consumed at least one of the
     * dense L1 sstables */
    int level1_ssts = atomic_load_explicit(&cf->levels[0]->num_sstables, memory_order_acquire);
    ASSERT_TRUE(level1_ssts < 2);

    ASSERT_EQ(tidesdb_close(db), TDB_SUCCESS);
    cleanup_test_dir();
}

